import MyShippingCard from "@/components/Card/myShippingCard";
import Spinner from "@/components/Loading/Spinner";
import { apiBaseUrl } from "@/config";
import { useCustomSWR } from "@/hooks/useCustomSWR";
import { useUserStore } from "@/stores/userStore";
import { Shipping, ShippingDetail } from "@/types";
import React, { useEffect } from "react";
import Cookies from "js-cookie";
import Rating from "@/components/Rating/Rating";

const MyShipping = () => {
  const userId = Cookies.get("userId");
  const { user, isLoading, error } = useUserStore();

  const shipping = useCustomSWR<Shipping>(
    userId ? `${apiBaseUrl}/shipping/${parseInt(userId) - 1}` : null
  );

  useEffect(() => {
    useUserStore.persist.rehydrate();
  }, []);

  return (
    <div className="flex flex-col">
      <div className="bg-primary w-full py-12 px-4 md:px-[5%] lg:px-[12%]">
        <h1 className="text-2xl font-semibold text-white">My Shipping List</h1>
      </div>
      <div className="mt-10 flex flex-col gap-8 px-4 md:px-[5%] lg:px-[12%] items-center">
        {error != "" && (
          <div>Error when getting the data, please refresh the page</div>
        )}
        {isLoading && <Spinner />}
        {user &&
          shipping.data &&
          shipping.data.shippingDetails.map((detail) => (
            <div key={detail.id}>
              <MyShippingCard shippingDetail={detail} userData={user} />
            </div>
          ))}
      </div>
    </div>
  );
};

export default MyShipping;
